)

func rateLimit(c *gin.Context) {
	ip := c.ClientIP()
	value := int(ips.Add(ip, 1))
	if value%50 == 0 {
		fmt.Printf("ip: %s, count: %d\n", ip, value)
	}
	if value >= 200 {
		if value%200 == 0 {
			fmt.Println("ip blocked")
		}
		c.String(http.StatusServiceUnavailable, "you were automatically banned :)")
		c.Abort()
		return
	}
}

func index(c *gin.Context) {
	c.Redirect(http.StatusMovedPermanently, "/room/hn")
}

func roomGET(c *gin.Context) {
	roomid := c.Param("roomid")
	nick := c.Query("nick")
	if len(nick) < 2 {
		nick = ""
	}
	if len(nick) > 13 {
		nick = nick[0:12] + "..."
	}
	c.HTML(http.StatusOK, "room_login.templ.html", gin.H{
		"roomid":    roomid,
		"nick":      nick,
		"timestamp": time.Now().Unix(),
	})
}

func roomPOST(c *gin.Context) {
	roomid := c.Param("roomid")
	nick := c.Query("nick")
	message := c.PostForm("message")
	message = strings.TrimSpace(message)

	validMessage := len(message) > 1 && len(message) < 200
	validNick := len(nick) > 1 && len(nick) < 14
	if !validMessage || !validNick {
		c.JSON(http.StatusBadRequest, gin.H{
			"status": "failed",
			"error":  "the message or nickname is too long",
		})
		return
	}

	post := gin.H{
		"nick":    html.EscapeString(nick),
		"message": html.EscapeString(message),
	}
	messages.Add("inbound", 1)
	room(roomid).Submit(post)
	c.JSON(http.StatusOK, post)
}

func streamRoom(c *gin.Context) {
	roomid := c.Param("roomid")
	listener := openListener(roomid)
	ticker := time.NewTicker(1 * time.Second)
	users.Add("connected", 1)
	defer func() {
		closeListener(roomid, listener)
		ticker.Stop()
		users.Add("disconnected", 1)
	}()

	c.Stream(func(w io.Writer) bool {
		select {
		case msg := <-listener:
			messages.Add("outbound", 1)
			c.SSEvent("message", msg)
		case <-ticker.C:
			c.SSEvent("stats", Stats())
		}
		return true
	})
}

package diagnostic

import (
	"bytes"
	"fmt"
	"os"
)

func CodeFrame(src []byte, line, column, context int) string {
	if context < 0 {
		context = 0
	}
	if line < 1 {
		line = 1
	}
	if column < 1 {
		column = 1
	}

	lines := bytes.Split(src, []byte("\n"))
	if len(lines) == 0 {
		return ""
	}
	for len(lines) > 1 && len(lines[len(lines)-1]) == 0 {
		lines = lines[:len(lines)-1]
	}
	if line > len(lines) {
		line = len(lines)
	}

	start := line - 1 - context
	if start < 0 {
		start = 0
	}
	end := line - 1 + context
	if end >= len(lines) {
		end = len(lines) - 1
	}

	width := digits(end + 1)
	var out bytes.Buffer
	for i := start; i <= end; i++ {
		ln := i + 1
		prefix := fmt.Sprintf("%*d | ", width, ln)
		if i == line-1 {
			prefix = fmt.Sprintf(">%*d | ", width, ln)
		}
		rawLine := string(lines[i])
		expandedLine := expandTabs(rawLine, 4)
		out.WriteString(prefix)
		out.WriteString(expandedLine)
		out.WriteByte('\n')

		if i == line-1 {
			caretPos := caretColumn(rawLine, column, 4)
			out.WriteString(fmt.Sprintf("%*s | ", width+1, ""))
			out.WriteString(spaces(caretPos))
			out.WriteByte('^')
			out.WriteByte('\n')
		}
	}
	return out.String()
}

func CodeFrameFromFile(file string, line, column, context int) (string, error) {
	b, err := os.ReadFile(file)
	if err != nil {
		return "", err
	}
	return CodeFrame(b, line, column, context), nil
}

func digits(n int) int {
	if n <= 0 {
		return 1
	}
	d := 0
	for n > 0 {
		n /= 10
		d++
	}
	return d
}

func spaces(n int) string {
	if n <= 0 {
		return ""
	}
	return string(bytes.Repeat([]byte(" "), n))
}

func expandTabs(s string, tabWidth int) string {
	if tabWidth <= 0 {
		tabWidth = 4
	}
	var out bytes.Buffer
	col := 0
	for _, r := range s {
		if r == '\t' {
			spaceCount := tabWidth - (col % tabWidth)
			out.Write(bytes.Repeat([]byte(" "), spaceCount))
			col += spaceCount
			continue
		}
		out.WriteRune(r)
		col++
	}
	return out.String()
}

func caretColumn(raw string, column, tabWidth int) int {
	if column <= 1 {
		return 0
	}
	if tabWidth <= 0 {
		tabWidth = 4
	}
	b := []byte(raw)
	bytePos := column - 1
	if bytePos > len(b) {
		bytePos = len(b)
	}
	prefix := string(b[:bytePos])
	col := 0
	for _, r := range prefix {
		if r == '\t' {
			col += tabWidth - (col % tabWidth)
			continue
		}
		col++
	}
	return col
}

